            proxy.plugin = "shadow-tls";
            proxy["plugin-opts"] = {
                host: shadowTLS.host,
                password: shadowTLS.password,
                version: shadowTLS.version,
            };
            if (proxy.alpn) {
                $set(proxy, "plugin-opts.alpn", proxy.alpn);
                delete proxy.alpn;
            }
